CREATE TABLE "video2"."renders" ("id" uuid NOT NULL DEFAULT gen_random_uuid(), "created_at" timestamptz NOT NULL DEFAULT now(), "creator_id" uuid NOT NULL, "org_id" uuid NOT NULL, "status" text NOT NULL, "fps" numeric NOT NULL, "width" integer NOT NULL, "height" integer NOT NULL, "work_slice_ms" integer NOT NULL, PRIMARY KEY ("id") , FOREIGN KEY ("creator_id") REFERENCES "identity"."users"("id") ON UPDATE restrict ON DELETE restrict, FOREIGN KEY ("org_id") REFERENCES "identity"."orgs"("id") ON UPDATE restrict ON DELETE restrict);COMMENT ON TABLE "video2"."renders" IS E'Resource tracking for renders';
CREATE EXTENSION IF NOT EXISTS pgcrypto;
